# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System;
using Microsoft.EntityFrameworkCore;

public class TicketService
{
    private readonly EventBookingContext _context;

    public TicketService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> CheckAndPurchaseTicketsAsync(int eventId, int quantity)
    {
        // Check if there are enough available seats
        var availableSeats = await _context.Events
            .Where(e => e.EventId == eventId)
            .Select(e => e.AvailableSeats)
            .FirstOrDefaultAsync();

        if (availableSeats < quantity)
        {
            // Not enough available seats, return false
            return false;
        }

        // Validate the purchase quantity
        var validationResult = _context.ValidateTicketPurchaseQuantity(eventId, quantity);
        if (!validationResult.IsValid)
        {
            // Quantity is invalid, return false
            return false;
        }

        // Update inventory and return true
        await _context.UpdateInventoryAsync(eventId, -quantity);
        return true;
    }
}